from dataclasses import dataclassfrom .detector import Detector@dataclass(slots=True)class Order:    """    CRIRES+ echelle order.    An order consists of the three detectors that together cover the    wavelength range of a single echelle order.    Parameters    ----------    number : int        Echelle order number.    detector1, detector2, detector3 : Detector        The three detectors belonging to the order.    """    number: int    detector1: Detector    detector2: Detector    detector3: Detector    # properties        @property    def detectors(self):        """List of detectors belonging to the order."""        return list(self)    @property    def wavelength_min(self):        """Minimum wavelength covered by the order."""        return min(            detector.wavelength_min            for detector in self        )    @property    def wavelength_max(self):        """Maximum wavelength covered by the order."""        return max(            detector.wavelength_max            for detector in self        )    @property    def wavelength_range(self):        """Minimum and maximum wavelength covered by the order."""        return (            self.wavelength_min,            self.wavelength_max,        )        @property    def width(self):        """Total wavelength coverage of the order."""        return (            self.wavelength_max -            self.wavelength_min        )        @property    def wavelength_center(self):        """Central wavelength of the order."""        return 0.5 * (            self.wavelength_min +            self.wavelength_max        )        # public methods        def __iter__(self):        """Iterate over the three detectors."""        return iter(            (                self.detector1,                self.detector2,                self.detector3,            )        )    # dunder methods        def __str__(self):        return (            f"Order {self.number}"        )